const now = new Date();
const date = `${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;
const tomorrow = new Date(now.getTime() + 86400000);
const tomorrowDate = `${String(tomorrow.getDate()).padStart(2,'0')}/${String(tomorrow.getMonth()+1).padStart(2,'0')}/${tomorrow.getFullYear()}`;
const weekday = ['Domingo','Segunda','Terca','Quarta','Quinta','Sexta','Sabado'][now.getDay()];
const tomorrowWeekday = ['Domingo','Segunda','Terca','Quarta','Quinta','Sexta','Sabado'][tomorrow.getDay()];

const doneToday = $('Tasks Done Today').all().map(i => {
  const name = i.json.property_name || 'Sem nome';
  const tags = i.json.property_tags || [];
  return `${name}${tags.length ? ' [' + tags.join(', ') + ']' : ''}`;
}).join('\n');
const doneCount = $('Tasks Done Today').all().length;

const overdue = $('Tasks Overdue').all().map(i => {
  const name = i.json.property_name || 'Sem nome';
  const due = i.json.property_due_date?.start || '';
  const tags = i.json.property_tags || [];
  const prio = tags.includes('Prioridade Alta') ? 'ALTA' : tags.includes('Prioridade Media') ? 'MEDIA' : '';
  return `${prio ? prio + ' ' : ''}${name} (due: ${due})`;
}).join('\n');
const overdueCount = $('Tasks Overdue').all().length;

const tasksTomorrow = $('Tasks Due Tomorrow').all().map(i => {
  const name = i.json.property_name || 'Sem nome';
  const tags = i.json.property_tags || [];
  const prio = tags.includes('Prioridade Alta') ? 'ALTA' : tags.includes('Prioridade Media') ? 'MEDIA' : '';
  return `${prio ? prio + ' ' : ''}${name}`;
}).join('\n');
const tomorrowCount = $('Tasks Due Tomorrow').all().length;

const dailyMemories = '';
const errorMemories = '';

const allMemoryContext = $('Memory Read (All Recent)').first().json.memoryContext || 'Nenhuma memoria recente.';

const prompt = `Hoje e ${date}, ${weekday}, 23:00. Night Shift para Ary Ribeiro.

${allMemoryContext}

CONTEXTO: Consultor IA, 3 verticais: TJ (advogados BR R$2.997/mes), TM (clinicas BR R$2.997/mes), CL (imobiliarias PT E497/mes). Meta Q2: E12.857 trimestral. Revenue actual: E0.

O QUE O DAILY BRIEF MANDOU FAZER HOJE:
${dailyMemories || '(nenhuma memoria do Daily Brief de hoje)'}

ERROS DETECTADOS HOJE:
${errorMemories || '(nenhum erro detectado)'}

O QUE FOI REALMENTE FEITO (${doneCount} tasks concluidas):
${doneToday || '(ZERO tasks concluidas hoje)'}

TASKS ATRASADAS (${overdueCount}):
${overdue || '(nenhuma task atrasada)'}

TASKS PARA AMANHA ${tomorrowDate} (${tomorrowCount}):
${tasksTomorrow || '(nenhuma task agendada para amanha)'}

ANALISA e gera o Night Shift Report:

REGRAS:
1. COMPARA o que o Daily Brief mandou fazer vs o que foi realmente feito
2. Se ACCAO #1 do Daily Brief nao foi concluida: identifica PORQUE (grande demais? nao sabe por onde comecar? nao e realmente prioridade?)
3. Se a mesma ACCAO #1 aparece em memorias de 3+ dias diferentes sem ser concluida (anti-streak): NAO repitas a instrucao. Em vez disso, DECOMPOE em micro-tasks de 30min cada
4. SCORE do dia: 0-10 baseado em execucao vs planeado
5. PRE-BRIEF para amanha: baseado no score, tasks de amanha, e padroes detectados
6. Se score < 5: pre-brief deve DECOMPOR a task #1 em passos de 30min
7. Se score >= 8: pre-brief mantem o plano
8. Brutalmente honesto, zero fluff, tom de accountability partner que nao aceita desculpas

FORMATO:

SCORE DO DIA: [X/10] [emoji]

EXECUCAO VS PLANO
- [o que foi pedido vs o que foi feito, sem meias palavras]

ANTI-STREAK [so se detectado]
- [task X esta como prioridade ha Y dias sem ser executada]
- [micro-decomposicao em blocos de 30min]

ERROS DO DIA [so se houve]
- [resumo de erros e impacto]

PRE-BRIEF AMANHA (${tomorrowWeekday} ${tomorrowDate})
- ACCAO #1: [especifica, concreta, com tempo estimado]
- PIPELINE: [2-3 bullets]
- [se score < 5: decomposicao em micro-tasks de 30min]

VEREDICTO
[1 frase dura sobre o dia que passou]

Maximo 350 palavras.`;

return [{ json: { prompt, timeout: 120000 } }];

const output = $('Claude Bridge').item.json.output;
const elapsed = $('Claude Bridge').item.json.elapsed_s;
const now = new Date();
const date = `${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;

let text = output
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/^- /gm, '• ')
  .replace(/---/g, '───');

text = `🌙 Night Shift — ${date}\n\n${text}\n\n───\n⏱️ Gerado em ${elapsed}s via Claude Code (with memory)`;

if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n(truncado)';
}

return [{ json: { text, number: '351913095597' } }];

const bridgeOutput = $input.first().json;

if (bridgeOutput.output && bridgeOutput.output.length > 10) {
  return [{ json: { output: bridgeOutput.output, elapsed_s: bridgeOutput.elapsed_s || 0, fallback: false, prompt: '' } }];
}

const prompt = $('Build Night Shift Prompt').first().json.prompt || '';
return [{ json: { output: '', elapsed_s: 0, fallback: true, prompt: prompt } }];

const response = $input.first().json;
const content = response.message?.content || 'Erro: Ollama nao respondeu';
return [{ json: { output: content + '\n\n⚠️ Gerado via Gemma3:27b (fallback local)', elapsed_s: 0 } }];
